import requests
import click

@click.command()
@click.option('--url', prompt='Enter the URL you want to shorten', help='The URL to shorten.')
def shorten_url(url):
    api_url = 'https://tinyurl.com/api-create.php?url='
    try:
        response = requests.get(api_url + url)
        if response.status_code == 200:
            click.echo(f'Shortened URL: {response.text}')
        else:
            click.echo('Failed to shorten URL. Please try again.')
    except Exception as e:
        click.echo(f'An error occurred: {e}')

if __name__ == '__main__':
    shorten_url()

